import inventory

def test_add_item():
    inv = {}
    inventory.add_item(inv, 'a', 5)
    assert inv == {'a': 5}
    inventory.add_item(inv, 'a', 3)
    assert inv == {'a': 8}

def test_remove_item():
    inv = {'a': 5}
    inventory.remove_item(inv, 'a', 2)
    assert inv == {'a': 3}
    inventory.remove_item(inv, 'a', 3)
    assert inv == {}

